-- Importación de citas de Terry Pratchett
-- Generado a partir del documento revisado
SET NAMES utf8mb4;
START TRANSACTION;

INSERT INTO citas_pratchett (cita, libro, personaje) VALUES
('Si quieres llegar a algo como bruja, tienes que aprender tres cosas: qué es real, qué no lo es y cuál es la diferencia. Brujas de viaje', 'Brujas de viaje', 'Yaya Ceravieja'),
('El progreso solo significa que las cosas malas suceden más rápido.', 'Brujas de viaje', NULL),
('Hay montones de lugares que son igual que el hogar. Pero solo uno de ellos es el lugar donde vives.', 'Brujas de viaje', NULL),
('Una mente humana es una nube tormentosa, un relampagueante conjunto de pensamientos, todos ellos ocupando una cantidad limitada de procesamiento cerebral. Es casi imposible averiguar qué piensa su propietario que está pensando, entre la contaminación de los prejuicios, los recuerdos, las preocupaciones, las esperanzas y los temores.', 'Brujas de viaje', NULL),
('La gente cree que son las personas las que dan forma a los cuentos. En realidad, es justo al revés.', 'Brujas de viaje', NULL),
('Se acabaron los cuentos. Se acabaron las hadas madrinas. Solo habrá personas que decidirán por sí mismas. Para bien o para mal. Acertando o equivocándose.', 'Brujas de viaje', 'Yaya Ceravieja'),
('No se puede ir por ahí construyendo un mundo mejor para la gente. Solo la gente puede construir un mundo mejor para la gente. Si no, es solamente una jaula.', 'Brujas de viaje', 'Yaya Ceravieja'),
('La mayoría de la gente viven sus vidas como una especie de borrón en torno al punto donde se encuentra su cuerpo, anticipándose al futuro o aferrándose al pasado. Suelen estar tan preocupados con lo que sucederá que solo averiguan lo que sucede cuando ya ha sucedido. Así son la mayor parte de las personas. Aprenden a tener miedo porque no saben lo que va a suceder. Y ya les está sucediendo.', 'Brujerías', NULL),
('En las llanuras donde había nacido, si uno daba patadas a la gente, la gente se las devolvía. En cambio, allí arriba, si le dabas una patada a alguien, este se apartaba y se limitaba a esperar a que se te cansara la pierna. ¿Cómo podía un rey pasar a la historia gobernando sobre semejante pueblo? No se los podía oprimir más de los que se puede oprimir a una manta.', 'Brujerías', NULL),
('Las cosas que intentan parecer cosas a menudo parecen más cosas que las cosas.', 'Brujerías', NULL),
('Yaya Ceravieja se enfadaba a menudo. Creía que era una de sus mejores cualidades. La ira genuina era una de las mejores fuerzas creativas del mundo. Pero había que aprender a controlarla. Eso no significaba que hubiera que disiparla, todo lo contrario: había que acumularla, permitir que desarrollara una cabeza pensante, dejar que invadiera los valles de la mente, y entonces, cuando toda la estructura parecía a punto de derrumbarse, había que abrir un pequeño escape en la base para que la corriente de ira dura como el acero alimentara las turbinas de la venganza.', 'Brujerías', 'Yaya Ceravieja'),
('Yaya Ceravieja no se había perdido. No era de esas personas que se pierden. Lo que pasaba era que, en aquel momento, aunque sabía muy bien dónde se encontraba, no conocía la ubicación del resto de las cosas.', 'Brujerías', 'Yaya Ceravieja'),
('Solo en los sueños somos libres. El resto del tiempo dependemos del presupuesto.', 'Brujerías', NULL),
('Las partículas de inspiración recorren el universo constantemente. De cuando en cuando, una de ellas va a caer sobre una mente perceptiva, que entonces inventa el ADN, o las sonatas para flauta dulce (...) La vida de muchísima gente transcurre sin que una sola de estas partículas se le acerque siquiera.
Otros son aún más desgraciados. Las reciben todas.', 'Brujerías', NULL),
('Entre los muchos lujos de los que el duque había prescindido a lo largo de su vida estaba el de la ignorancia. Le gustaba sentir que sabía lo que estaba pasando. Las gloriosas inseguridades de la existencia no le atrían en absoluto.', 'Brujerías', NULL),
('Yaya nunca había dedicado mucho tiempo a las palabras. Eran insustanciales. Ahora deseaba haberles prestado más atención. Eran suaves como el agua, pero también tan poderosas como el agua, inundaban al público, erosionaban los matices de la realidad y arrasaban el pasado de sus oleadas.', 'Brujerías', NULL),
('Creo que la responsabilidad se adquiere cuando te haces mayor. Como las varices.', 'Brujerías', NULL),
('Los días se sucedían con paciencia. En el principio del multiverso, habían intentado pasar todos a la vez, pero la cosa no funcionó.', 'Brujerías', NULL),
('Lo malo es que porque una cosa sea obvia no quiere decir que sea cierta.', 'Brujerías', NULL),
('En noches como esta se llevan a cabo acciones malvadas. También buenas, claro. Pero las malas ganan de largo.', 'Brujerías', NULL),
('Te estarás preguntando si voy a cortarte la garganta de verdad - jadeo Magrat - Yo tampoco lo sé. Imagina cuánto nos divertiremos averiguándolo juntos.', 'Brujerías', 'Magrat Ajostiernos'),
('Vitoller siempre movía los brazos cuando hablaba. Si le ataran las manos a la espalda, se quedaría mudo.', 'Brujerías', 'Olwyn Vitoller'),
('Magrat se preguntó que se sentiría al pasarse toda la vida haciendo algo que no querías hacer. Era como estar muerto, razonó, o solo que peor, porque estás vivo para sufrirlo', 'Brujerías', 'Magrat Ajostiernos'),
('Este libro fue escrito usando palabras 100% recicladas.', 'Brujerías', NULL),
('–Sí, señor, pero es que yo me resisto, me resisto, señor. ¿Que me bañen, señor? ¿Y que lo hagan mujeres? ¿Mirándome la trompeta y los bolos? ¡Menuda desvergüenza! ¡Todo el mundo sabe que el jabón mata las refulgencias naturales, señor! ¡Oh, señor! ¡Me tienen aquí prisionero, señor! ¡Me han hecho una pantalonectomía, señor!', 'Cartas en el asunto', NULL),
('A veces, las palabras también necesitan música. A veces, las descripciones no bastan. Los libros deberían escribirse con banda sonora, como las películas.', 'Cavadores', NULL),
('Por supuesto, había un montón de preguntas, pero de momento no importaban las respuestas; bastaba con disfrutar de las preguntas y saber que el mundo estaba lleno de cosas sorprendentes, y que él no era ninguna rana.', 'Cavadores', NULL),
('El mundo ya era suficientemente complicado sin necesidad de que nadie fuese por ahí tratando continuamente de mejorarlo.', 'Cavadores', NULL),
('Había tenido que obligar a los gnomos a pensar de manera distinta para abandonar la Tienda. Los cambios eran necesarios. Cambiar estaba bien. Él estaba por completo a favor de los cambios.
A lo que era absolutamente reacio era a que las cosas no siguieran como estaban.', 'Cavadores', NULL),
('—El Times parece creer que pretendo nacionalizar el Banco Real -respondió Vetinari.
—¿Nacionalizar? -dijo Húmedo.
—Robar -tradujo Vetinari. No sé de dónde salen esos rumores.
—Supongo que hasta los tiranos tienen enemigos -dijo Húmedo.', 'Dinero a mansalva', 'Lord Vetinari'),
('El mundo está lleno de cosas que valen más que el oro. Pero lo excavamos como posesos para luego enterrarlo en un agujero distinto. ¿Qué sentido tiene eso? ¿Qué somos, urracas? ¿Lo que cuenta es que brille? ¡Por los cielos, las patatas valen más que el oro!', 'Dinero a mansalva', NULL),
('Hagamos dinero que no se base en un truco de la geología sino en el ingenio de la mano y el cerebro.', 'Dinero a mansalva', NULL),
('Me pregunto si soy de verdad un cabrón o solo es que se me da muy bien pensar como si lo fuera.', 'Dinero a mansalva', NULL),
('Un error, señor, es peor que un pecado, pues un pecado a menudo depende de la opinión, el punto de vista o hasta del momento, mientras que un error es una evidencia que pide a gritos que la corrijan.', 'Dinero a mansalva', NULL),
('El tiempo es una droga. Demasiado te mata.', 'Dioses menores', NULL),
('Ser la mano derecha de Ymor era como si te azotaran amablemente hasta la muerte con cordones perfumados de zapatos.', 'El color de la magia', 'Muerte'),
('Se dice que, cuando un mago está a punto de morir, la Muerte en persona se presenta a recogerle, en vez de dejar la tarea a un subordinado, como la Enfermedad o el Hambre, que es lo más corriente.', 'El color de la magia', 'Muerte'),
('Estaba muy bien apoyarse en la lógica pura, decir que el universo estaba regido por la lógica y la armonía de los números, pero lo obvio era que el disco atravesaba el espacio a lomos de una tortuga gigante, y que los dioses tenían la costumbre de rondar por las casas de los ateos para destrozarles las ventanas.', 'El color de la magia', NULL),
('Más tarde, aquella noche, se concentró tanto en sus estudios que olvidó el tema por completo.', 'El color de la magia', NULL),
('Hummm, titubeó su imaginación al poco rato.
No era que el troll resultase aterrador. En vez de la monstruosidad putrefacta y llena de tentáculos que esperaba, Rincewind se encontró mirando a un anciano regordete, pero no particularmente feo, que podría pasar por normal en las calles de la ciudad. Siempre, claro está, que el resto de los transeúntes estuvieran acostumbrados a ver ancianos aparentemente compuestos de agua y muy poca cosa más. Era como si el océano hubiera decidido crear vida sin pasar por todo el tedioso proceso de la evolución, limitándose a formar un bípedo con parte de sí mismo, y enviarlo a chapotear por la playa. El troll era de un agradable color azul transparente.', 'El color de la magia', 'Rincewind'),
('Cuando pienso que puedo morir sin haber visto ni una centésima parte de lo que existe, me siento... —hizo una pausa para buscar la palabra adecuada—. Bueno, humilde, sí. Pero también muy furioso, claro.', 'El color de la magia', NULL),
('Los habitantes habían hecho de la profesión de observador interesado un auténtico arte.', 'El color de la magia', NULL),
('Un doble arco iris empezaba a aparecer. Cerca del inicio de la Catarata Periférica estaban los siete colores menores, que chispeaban y bailaban entre la espuma de los mares moribundos.
Pero palidecían en comparación con la franja más ancha que flotaba tras ellos, sin dignarse a compartir el mismo espectro.
Era el Color Rey, del cual todos los colores menores eran simples reflejos parciales e insulsos. Era el octarino, el color de la magia. Estaba vivo, brillante y vibrante. Y era, sin discusiones, el pigmento de la imaginación: porque, allí donde aparecía, indicaba que la simple materia estaba al servicio de los poderes de la mente mágica. Era la esencia misma del encantamiento.
Pero a Rincewind siempre le parecía una especie de púrpura verdoso.', 'El color de la magia', 'Rincewind'),
('Rincewind trató de cerrar los ojos, pero la imaginación tenía párpados, y la muy maldita siguió mirando fijamente', 'El color de la magia', 'Rincewind'),
('Una alternativa, sostenida sobre todo por los más religiosos, era que A''Tuin se arrastraba desde el Lugar de Nacimiento hacia el Momento de la Cópula, al igual que todas las estrellas del cielo que, evidentemente, también viajaban a lomos de tortugas gigantes. Cuando llegaran, copularían breve y apasionadamente por primera y única vez, y de tan ardiente unión nacerían nuevas tortugas que transportarían nuevos mundos. Se conocía esta hipótesis como Teoría del Big Bang.', 'El color de la magia', NULL),
('Una de las desventajas de estar muerto es que uno queda libre de las ligaduras del tiempo. Por tanto, puedo ver lo que ha sucedido y sucederá, todo al mismo tiempo. Aunque claro, ahora sé que, a efectos prácticos, el Tiempo no existe en absoluto. -Eso no parece una desventaja...- ¿Tú crees? Imagina que cada momento sea uno, que resulte a la vez un recuerdo lejano y una sorpresa desagradable, y ya verás. ¿Comprendes ahora a qué me refiero?', 'El color de la magia', NULL),
('Eso es lo estúpido de la magia, ¿sabes? Te pasas veinte años aprendiendo el hechizo que hace aparecer vírgenes desnudas en tu dormitorio y, cuando lo consigues, estás tan envenenado por los vapores de mercurio, tan ciego de leer grimorios viejos, que no te acuerdas de lo que viene después.', 'El color de la magia', NULL),
('los dioses tenían la costumbre de rondar por las casas de los ateos para destrozarles las ventanas.', 'El color de la magia', NULL),
('La magia nunca muere, solo desaparece.', 'El color de la magia', NULL),
('Todos los héroes del Mar Circular pasaban tarde o temprano por Ankh-Morpork. La mayoría venía de las tribus bárbaras, cerca de las heladas tundras del Eje, cuya economía se basaba en la exportación de héroes.', 'El color de la magia', NULL);

INSERT INTO citas_pratchett (cita, libro, personaje) VALUES
('Ser la mano derecha de Ymor era como si te azotaran amablemente hasta la muerte con cordones de zapatos perfumados.', 'El color de la magia', 'Muerte'),
('Pero, por fin se me ocurrió que tarde o temprano todos los hombres deben morir. Al final, todo muere. «Pueden retrasarme, pero no evitarme», me dije. «¿Por qué preocuparse?»', 'El color de la magia', NULL),
('La desaparición brusca de varios quintillones de átomos, de un universo en el que todos modos no tenían derecho a estar, provocó al instante un desequilibrio en la armonía de la totalidad, que esta intentó compensar a la desesperada, aunque acabó con unas cuantas subrealidades en el proceso. Grandes oleadas de magia pura hirvieron incontrolables bajo los mismos fundamentos del multiverso, y escaparon por cada ranura posible hacia dimensiones más tranquilas. A su paso, provocaron novas, supernovas, colisiones estelares, la emigración de bandadas de gansos y el hundimiento de continentes imaginarios. Al otro extremo del tiempo, algunos mundos presenciaron puestas de sol de un crepitante color octarino, cuando partículas con una fuerte carga mágica atravesaron rugientes la atmósfera. En el halo cometario que rodea el Sistema Gélido de Zeret, un noble cometa murió como un príncipe, atravesando en llamas el cielo.', 'El color de la magia', NULL),
('Desde que tenía dos años, le habían cautivado las imágenes de aquellas bestias que aparecían en El Libro Octarino de las Hadas. Su hermana le había dicho que no existían en realidad, y él recordaba la amarga decepción que sufrió. Decidió que, si en el mundo no se encontraban aquellas hermosas criaturas, el mundo no era ni la mitad de bueno de lo que podría ser. Y más tarde, cuando empezó a trabajar como aprendiz con Ninereeds, el Maestro Contable, cuya mentalidad gris era todo lo que no eran los dragones, ya no le quedó tiempo para soñar.', 'El color de la magia', NULL),
('—Claro —asintió Rincewind—, Lo que más les gusta a los héroes son ellos mismos.', 'El color de la magia', 'Rincewind'),
('Entonces, la Muerte recordó lo que iba a suceder aquella misma noche. No sería correcto decir que sonrió, ya que, en cualquier caso, sus rasgos estaban perpetuamente congelados en una sonrisa calcárea. Pero empezó a tararear una tonadilla, tan alegre como el entierro de un apestado, y —deteniéndose solo para robarle la vida a una mosca de mayo, y una de sus nueve vidas a un gato que se escondía cobardemente bajo la caseta de pescado (todos los gatos ven el octarino)—, la Muerte giró sobre sus talones y echó a andar hacia el Tambor Roto.', 'El color de la magia', 'Muerte'),
('Muchas veces se ha dicho que, aquellos que son sensibles a la radiación del octarino —el octavo color, el Pigmento de la Imaginación— pueden ver cosas que resultan invisibles para los demás.', 'El color de la magia', NULL),
('—No me has comprendido bien —dijo el mago con voz fatigada—. En cualquier otro momento, me darías tanto miedo que me temblarían las rodillas, pero es que ahora tengo una sobredosis de terror. No te preocupes; cuando lo supere, tendré tiempo de asustarme convenientemente de ti.', 'El color de la magia', NULL),
('En este punto de la explicación es cuando el lenguaje se rinde y se va a tomar un trago.', 'El color de la magia', NULL),
('…cuando empezó a trabajar como aprendiz con Ninereeds, el Maestro Contable, cuya mentalidad gris era todo lo que no eran los dragones, ya no le quedó tiempo para soñar.', 'El color de la magia', NULL),
('…era el reverso de una moneda en la que Bien y Mal ocupaban la misma cara.', 'El color de la magia', NULL),
('…era prácticamente un intelectual según los estándares del Eje, ya que podía pensar sin mover los labios.', 'El color de la magia', NULL),
('…cuya economía se basaba en la exportación de héroes.', 'El color de la magia', NULL),
('Cualquiera le habría tomado por un simple aprendiz de hechicero que había escapado de su maestro por rebeldía, aburrimiento, miedo o un gusto persistente por la heterosexualidad.', 'El color de la magia', NULL),
('En la otra orilla del río, los ciudadanos de Ankh, más ricos y dignos, reaccionaban con valentía ante la situación demoliendo febrilmente los puentes.', 'El color de la magia', NULL),
('…si se organizara el caos más completo, este tipo se subiría a una colina bajo una tormenta de truenos, con una armadura de cobre empapada, gritando «¡Todos los dioses son unos bastardos!', 'El color de la magia', NULL),
('Era la esencia misma del encantamiento. Pero a Rincewind siempre le parecía una especie de púrpura verdoso', 'El color de la magia', 'Rincewind'),
('Algunos piratas conseguían la inmortalidad por sus grandes crueldades o proezas. Otros conseguían la inmortalidad gracias a la gran riqueza amasada. Pero el capitán había decidido mucho tiempo antes que quería alcanzar la inmortalidad por no haber muerto.', 'El color de la magia', NULL),
('El Mundodisco ofrece vistas mucho más impresionantes que cualquiera de las que se pueden encontrar en otros universos, construidos por Creadores con menos imaginación, pero más aptitudes mecánicas', 'El color de la magia', NULL),
('Como bien sabía por experiencia, solo era cuestión de tiempo que el equilibrio del universo volviera a sus cauces normales y empezaran a sucederle las cosas terribles de siempre.', 'El color de la magia', NULL),
('En el Gremio de Asesinos, la promoción se efectuaba mediante examen competitivo, y la práctica era la asignatura más importante. Para ser exactos, la única.', 'El color de la magia', NULL),
('Jamás se le habría ocurrido negar que era un cobarde y un incompetente, que ni siquiera se daba buena maña para fracasar.', 'El color de la magia', NULL),
('Éste había optado por un método de monta que implicaba caerse de la silla cada pocos segundos.', 'El color de la magia', NULL),
('Pues tienes un rostro que engaña. Yo que tú, lo controlaría.', 'El color de la magia', NULL),
('—¿Qué es lo que más les gusta a los héroes?
—¿El oro?
—No... Lo que más les gusta a los héroes son ellos mismos.', 'El color de la magia', NULL),
('Los Altos Antiguos, ante quienes hasta los dioses tenían que responder, tomaron drásticas cartas en el asunto. Los dioses se vieron relegados a las zonas superiores, los hombres fueron recreados bastante más pequeños, y buena parte de la vieja magia fue arrancada de la tierra. Esto no resolvió el problema de aquellas zonas del disco que, durante las guerras, habían sufrido el impacto directo de un hechizo. La magia fue desvaneciéndose lentamente, a lo largo de los milenios. Y, al descomponerse, liberó miríadas de partículas subastrales que distorsionaron gravemente la realidad circundante...', 'El color de la magia', NULL),
('Demasiado fanfarrón para ser un mago de tercera -murmuro. No me has comprendido bien -dijo el mago con voz fatigada-. En cualquier otro momento, me darías tanto miedo que me temblarían las rodillas, pero es que ahora tengo una sobredosis de terror. No te preocupes; Cuando lo supere, tendré tiempo de asustarme convenientemente de ti.', 'El color de la magia', NULL),
('En lo más profundo de su mente, un mal presentimiento empezaba a cobrar forma. Por ejemplo, imaginó cómo se sentiría un zorro enfrentado a un rebaño de ovejas furiosas. Unas ovejas que, además, podían contratar a lobos.', 'El color de la magia', NULL),
('Hemos entrado en una zona con un alto índice de magia. No me preguntes cómo. Había una vez un campo mágico verdaderamente poderoso que debió de generarse aquí, y estamos notando los efectos secundarios. -Exacto -dijo un arbusto al pasar.', 'El color de la magia', NULL),
('El demonio tosió, inquieto (los demonios no respiran. Pero cualquier ser inteligente, respire o no, tose inquieto en algún momento de su vida. Y, por lo que veía el demonio, este era uno más que adecuado).', 'El color de la magia', NULL),
('En opinión del mago, los dragones debían existir del todo o no existir en absoluto. Un dragón que solo existía a medias era peor que cualquiera de los dos extremos.', 'El color de la magia', NULL),
('—Hay otra ruta de acceso.
—No lo sabía.
—¿En serio? —replicó Brocando—. Me dejas de piedra. Con lo que nos costó construir un pasaje secreto y al final se nos olvidó comunicárselo al emperador. Recuérdame que le envíe una nota.', 'El pueblo de la Alfombra', 'Brocando'),
('[...] lo de que se acaben los libros de historia no es lo peor de todo, joven. Yo diría que lo peor es morir —declaró lady Vortex—. La historia ya cuidará solita de sí misma.', 'El pueblo de la Alfombra', NULL),
('Siempre hay un después [...] La cuestión es conseguir el después deseado.', 'El pueblo de la Alfombra', NULL),
('Nada debe ocurrir necesariamente. La historia no es algo que se vive. Es algo que se hace. Una decisión. Una persona. En el momento adecuado. Nada es demasiado pequeño para marcar la diferencia. Cualquier cosa puede cambiarse.', 'El pueblo de la Alfombra', NULL),
('Hormiga siempre decía que había ciertas cosas que debían importarte lo bastante para atreverte a hacerlas mal.', 'El pueblo de la Alfombra', NULL),
('Snibril pensó que, si hay algo casi tan malo como descubrir que tus peores miedos se hacen realidad, es descubrir que eso no va a suceder.', 'El pueblo de la Alfombra', NULL),
('No era lo que entendemos por ser idiota. Su cerebro acababa alcanzando su destino. Simplemente, llegaba a él por el camino largo.', 'El pueblo de la Alfombra', NULL),
('La luz piensa que viaja más rápido que cualquier cosa, pero está equivocada. No importa cómo de rápido viaje la luz, siempre encuentra que la oscuridad ha llegado primero, y está esperándola.', 'El segador', NULL),
('Cuando se ve lo que hace la vida con la gente, usted no parece tan malo.', 'El segador', NULL),
('Nadie ha muerto del todo hasta que mueren las ondulaciones que ha provocado en este mundo: hasta que se para el reloj al que dio cuerda, hasta que fermenta el vino que preparó, hasta que se recoge la cosecha que plantó.', 'El segador', NULL),
('Nunca había aprendido nada observando lo que los humanos se decían unos a otros: para ellos, el lenguaje no era más que una manera de ocultar lo que pensaban.', 'El segador', NULL),
('Siempre estoy solo. Pero ahora lo que quiero es estar solo a solas.', 'El segador', NULL),
('Solo erótico. Nada perverso. Es la diferencia entre usar una pluma y usar un pollo.', 'Eric', NULL),
('Astfgl había dejado atrás las fases iniciales de la furia y ahora se encontraba en esa laguna calmada de ira donde la voz es tranquila, los modales son comedidos y corteses y solamente un ligero resto de saliva en la comisura de la boca delata el infierno interior.', 'Eric', NULL),
('El siguiente decía: «Pensé que te gustaría».
Eric estaba encima de: «Es por los niños».
—Qué raro, ¿no? —dijo—. ¿Por qué habrán hecho esto?
—Creo que pretenden ser buenas intenciones —dijo Rincewind.
Aquel era un camino al infierno, y después de todo los demonios son tradicionalistas.', 'Eric', 'Rincewind'),
('La razón por la que los ricos eran ricos, razonaba Vimes, era que se las arreglaban para gastar menos dinero.
Tomemos el caso de las botas, por ejemplo. Un par de botas de cuero realmente buenas costaba cincuenta dólares. Pero un par de botas, las que aguantaban más o menos bien durante una o dos estaciones y luego empezaban a llenarse de agua en cuanto cedía el cartón, costaban alrededor de diez dólares. Aquella era la clase de botas que Vimes compraba siempre, y las llevaba hasta que las suelas quedaban tan delgadas que le era posible decir en qué lugar de Ankh-Morpork se encontraba durante una noche de niebla solo por el tacto de los adoquines.
Pero el asunto era que las botas realmente buenas duraban años y años. Un hombre que podía permitirse gastar cincuenta dólares disponía de un par de botas que seguirían manteniéndole los pies secos dentro de diez años, mientras que un pobre que solo podía permitirse comprar botas baratas se habría gastado cien dólares en botas durante el mismo tiempo y SEGUIRÍA TENIENDO LOS PIES MOJADOS.', 'Hombres de armas', 'Sam Vimes'),
('En estos momentos, el axioma "Los hombres honrados no tienen nada que temer de la policía" está siendo revisado por la Junta de Apelación de Axiomas.', 'Hombres de armas', NULL),
('[...] si un hombre te tiene totalmente a su merced, entonces aférrate a la esperanza de que ese hombre sea malvado. Porque a los malvados les encanta el poder, el poder sobre las personas, y quieren verte pasar miedo. Quieren que sepas que vas a morir. Así que hablarán. Se regodearán.
Verán cómo te retuerces. Irán posponiendo el momento del asesinato de la misma manera en que otro hombre irá posponiendo el momento de encender un buen puro.
Por eso debes aferrarte a la esperanza de que tu captor sea un hombre malvado. Porque un hombre bueno te matará sin llegar a abrir la boca.', 'Hombres de armas', NULL),
('—Sueñas con volar —dijo.
—Oh, sí. Entonces los hombres serían libres de verdad. Desde el aire, no hay límites ni fronteras. No podría haber más guerra, porque el cielo es inacabable. Cuan felices seríamos, solo con que pudiéramos volar.', 'Hombres de armas', NULL);

INSERT INTO citas_pratchett (cita, libro, personaje) VALUES
('Algo como aquello, algo peligroso, ¿por qué no limitarse a librarse de ello? ¿Por qué conservarlo? Pero eso no era propio de la naturaleza humana, ¿verdad? A veces las cosas eran demasiado fascinantes para que se las destruyera.', 'Hombres de armas', NULL),
('—Oh, no era ningún idiota [...] Lo que le pasaba era que tenía una mente tan afilada que siempre se cortaba con ella, como solía decir mi abuela.', 'Hombres de armas', NULL),
('Si el Creador hubiera dicho «Hágase la luz» en Ankh—Morpork, no hubiese llegado más allá de eso porque todo el mundo habría empezado a preguntar: «¿De qué color?».', 'Hombres de armas', NULL),
('Le hubiese gustado poder coger aquel momento y guardarlo dentro de un gran libro, para que cuando fuese viejo pudiera volver a sacarlo ocasionalmente de entre sus páginas y recordarlo.', 'Hombres de armas', NULL),
('[...] como ocurre con todas las buenas venganzas, realmente ya no necesitaba de una razón. Bastaba con que siempre hubiera existido.', 'Hombres de armas', NULL),
('La vida entera es como mirar una película. Solo que es como si siempre estuvieras dentro de los primeros diez minutos de la película, y nadie te dirá la trama, así que tienes que resolverlo todo por tus propias pistas.', 'Imágenes en acción', NULL),
('La vida entera es como ver una película, pensó. Lo que pasa es que siempre parece como si hubieras llegado diez minutos después de que empezara, y nadie te cuenta de qué va, de manera que lo tienes que ir averiguando todo sobre la marcha, a medida que la ves. Y nunca, nunca, tienes ocasión de quedarte en el asiento para el segundo pase.', 'Imágenes en acción', NULL),
('Victor despertó. Era como salir lentamente de una nube color rosa, o de un magnífico sueño que uno no puede recordar a la luz del día por mucho que lo intente, dejándote con una terrible sensación de ausencia, de pérdida. Sabes instintivamente que nada, nada de lo que vayas a experimentar a lo largo del día, será ni siquiera la mitad de agradable que ese sueño.', 'Imágenes en acción', 'Victor Tugelbend'),
('Ruina inhaló profundamente el espeso aire de la ciudad. Aire auténtico. Había que viajar mucho para encontrar un aire más auténtico que el de Ankh-Morpork. Solo con respirarlo, se notaba que otras personas también habían estado haciéndolo durante miles de años.', 'Imágenes en acción', NULL),
('La pereza vulgar y corriente no es más que la ausencia total de esfuerzo. Victor estaba por encima de eso desde hacía ya mucho tiempo, había superado la ociosidad normal y había salido por el otro extremo. Dedicaba más esfuerzos a evitar trabajar que los que la mayoría de la gente dedicaba a la profesión más dura.', 'Imágenes en acción', 'Victor Tugelbend'),
('En realidad, Tata Ogg había hecho muchísimo de absolutamente todo, y se consideraba que tenía una mente tan abierta que podía sacarse por las orejas y usarla para atar un sombrero.', 'La corona del pastor', NULL),
('Siempre había mantenido que la huida era el mejor medio de supervivencia. En los viejos tiempos, según decía la teoría, la gente que se enfrentaba a tigres de dientes de sable hambrientos se dividía en dos categorías: los que huían y los que se quedaban allí diciendo «¡Qué magnífico animal!» o bien «Gatito, gatito».', 'La luz fantástica', NULL),
('Por supuesto que estoy cuerdo, cuando los árboles comienzan a hablarme, no respondo.', 'La luz fantástica', NULL),
('Los profesores de Rincewind habían coincidido en afirmar que este era un mago nato de la misma manera que los peces son alpinistas natos.', 'La luz fantástica', 'Rincewind'),
('—¿Cuáles son las grandes cosas que un hombre puede encontrar en la vida?
—Agua caliente, buenos dientes y papel higiénico suave.', 'La luz fantástica', 'Cohen el Bárbaro'),
('El universo, según decían, dependía para su funcionamiento del equilibrio de cuatro fuerzas que ellos identificaban como encanto, persuasión, inseguridad y mala leche.', 'La luz fantástica', NULL),
('Reflexionó, y no por primera vez, en que ser espadachina tenía muchos inconvenientes, quizá uno de los peores el hecho de que los hombres no te tomaban en serio hasta que los matabas, momento en el cual la cosa ya no tenía demasiada importancia.', 'La luz fantástica', 'Herrena'),
('La Universidad Invisible jamás había admitido a mujeres, poniendo excusas del tipo "problemas con los cuartos de baño", pero la auténtica razón era un temor jamás expresado de que, si se permitiera a las mujeres andar por ahí haciendo magia, probablemente se les daría embarazosamente bien.', 'La luz fantástica', NULL),
('Nadie sabe por qué, pero la mayoría de los objetos más misteriosos se compran en tiendas que aparecen y, tras una vida comercial más breve que la de una empresa de venta por correo, se desvanecen como el humo.', 'La luz fantástica', NULL),
('Lo importante de tener muchas cosas que recordar es ir a algún sitio a recordarlas, ¿comprendes? Tienes que detenerte. No has estado en ninguna parte hasta que no vuelves a casa.', 'La luz fantástica', NULL),
('El sonido deliberado, turbador, preparado para hacerte comprender con toda claridad que cada tic y cada tac te están quitando un segundo de vida.', 'La luz fantástica', NULL),
('Es un animal. Los animales no pueden asesinar. Solo nosotras las razas superiores podemos asesinar. Esa es una de las cosas que nos distinguen de los animales.', 'Lores y damas', NULL),
('Lo que no muere no puede vivir. Lo que no vive no puede cambiar. Lo que no cambia no puede aprender.', 'Lores y damas', NULL),
('No tengo nada contra los dioses y las diosas, siempre que sepan quedarse en su sitio. Pero tienen que ser los que nosotros hagamos. De esa manera podremos desmontarlos para volver a usar las piezas cuando ya no los necesitemos', 'Lores y damas', NULL),
('Ah, las obras y los libros… No puedes darles la espalda en ningún momento, porque entonces se volverán contra ti.', 'Lores y damas', NULL),
('—[...]Una muerte segura.
—Como todas las muertes, en cualquier caso —dijo Ridcully—. Eso es lo que tiene la Muerte: la certeza.', 'Lores y damas', 'Mustrum Ridcully'),
('—Pero tengan en cuenta —dijo Ponder— que los cementerios están llenos de gente que fue más valiente que sensata.
—Ook.
—¿Qué ha dicho? [...]
—Creo que ha dicho «Tarde o temprano los cementerios están llenos de todo el mundo»', 'Lores y damas', NULL),
('—Tienes menos moral que un gato, Gytha Ogg.
—Vamos, Esme, ya sabes que eso no es verdad.
—De acuerdo. Entonces diré que tienes la moral de un gato.
—Eso está mejor.', 'Lores y damas', NULL),
('Belleza. Gracia. Eso es lo que importa. Si los gatos parecieran ranas, enseguida nos daríamos cuenta de lo desagradables y crueles que son esos pequeños bastardos.', 'Lores y damas', NULL),
('Las personas que no necesitan gente necesitan gente a su alrededor para saber que son el tipo de personas que no necesitan gente.', 'Mascarada', NULL),
('¿Yo matando a la gente?, repitió la Muerte visiblemente ofendido. La gente se hace matar sola, es un asunto de ellos. Yo me limito a tomar las riendas a partir de ese momento. Al fin y al cabo, este mundo sería una soberana estupidez si la gente se hiciera matar sin morirse, ¿no te parece?', 'Mort', 'Muerte'),
('Debería existir una palabra para denominar ese breve período que sigue al despertar, cuando la mente está llena de la nada cálida y rosada. Uno permanece allí, acostado, libre de todo pensamiento, salvo por la creciente sospecha de que hacia uno se dirigen, como un guantazo recibido en plena noche en un callejón, todos los recuerdos de los que uno preferiría prescindir, y que se reducen al hecho de que el único factor mitigante de nuestro horrible futuro es la certeza de que será brevísimo.', 'Mort', NULL),
('Esos que ves allí son mortales -prosiguió la Muerte-. Estarán en este mundo apenas unos cuantos años y se los pasan complicándose la vida. Es fascinante. Sírvete un pepinillo.', 'Mort', 'Muerte'),
('Recordaba que sería invocado a una existencia renuente en el momento en que viviera la primera criatura, y que tendría la certeza de que viviría más que la vida misma hasta que el último ser del universo hubiera acudido a recibir su recompensa, y entonces, a él le correspondería, hablando en sentido figurado, colocar las sillas sobre las mesas y apagar todas las luces.', 'Mort', 'Muerte'),
('NO EXISTE LA JUSTICIA, SOLO EXISTO YO', 'Mort', 'Muerte'),
('"Son demasiadas las jóvenes que se lanzan en los brazos del primer muchacho que las despierta después de un sueño de cien años".', 'Mort', NULL),
('"La gente no quiere ver aquello cuya existencia le resulta imposible".', 'Mort', NULL),
('La historia tiene la costumbre de cambiar a las personas que se creen que la están cambiando a ella.', 'Mort', NULL),
('—Muy bien —dijo Susan—. No soy tonta. Me estás diciendo que los humanos necesitan… fantasía para hacer la vida soportable, ¿no?
¿DE VERAS? ¿CÓMO SI FUERA UNA ESPECIE DE PÍLDORA ROSA? NO. LOS HUMANOS NECESITAN LA FANTASÍA PARA SER HUMANOS. PARA SER EL PUNTO DONDE EL ÁNGEL QUE CAE SE ENCUENTRA CON EL SIMIO QUE SE ALZA.
—¿Hadas de los dientes? ¿Papá Puerco? ¿Pequeñas…?
SÍ. A MODO DE PRÁCTICA. HAY QUE EMPEZAR APRENDIENDO A CREER EN LAS MENTIRAS PEQUEÑAS.
—¿Para que podamos creer en las grandes?
SÍ, LA JUSTICIA. LA COMPASIÓN. EL DEBER. ESAS COSAS.
—¡No son lo mismo en absoluto!
¿ESO CREES? ENTONCES COGE EL UNIVERSO Y MUÉLELO HASTA QUE NO SEA MÁS QUE UN POLVILLO FINO Y PÁSALO POR EL MÁS FINO DE LOS TAMICES Y ENTONCES ENSÉÑAME UN SOLO ÁTOMO DE JUSTICIA, UNA MOLÉCULA DE COMPASIÓN. Y SIN EMBARGO… La Muerte hizo un gesto con la mano. Y SIN EMBARGO ACTUÁIS COMO SI EXISTIERA UN ORDEN IDEAL EN EL MUNDO. COMO SI HUBIERA UNA… UNA CORRECCIÓN EN EL UNIVERSO POR LA CUAL ESTE PUEDE SER JUZGADO.', 'Papá Puerco', 'Susan Sto Helit'),
('—¿Quién es usted?
—Ah, pues me alegro de que me lo preguntes. ¡Soy tu peor pesadilla!- Dijo Teatime alegremente.
El hombre se estremeció
—¿Se refiere...a la del repollo gigante y esa cosa parecida a un cuchillo que runrunea?', 'Papá Puerco', NULL),
('Los caballos, en opinion de la Muerte, no tenian que sonrreir. Cuando un caballo sonrreia era porque estaba tramando algo.', 'Papá Puerco', 'Muerte'),
('«Las personas pintan el mundo que querrían sobre el mundo que es.»', 'Perillán', NULL),
('«...la verdad es una niebla en la que un hombre ve la hueste celestial y otro ve un elefante volador.»', 'Perillán', NULL),
('El hecho de que alguien sea miembro de una minoría étnica no significa que no pueda ser un pequeño imbécil desagradable.', 'Pies de barro', NULL),
('Aquello no era simple enfado o un ataque de mal genio. Era ira, la auténtica ira de la mejor cosecha de la antigüedad. Los clásicos siempre habían afirmado que se podía distinguir la verdadera ira de las imitaciones baratas porque hervía y burbujeaba, y en aquellos momentos Dios parecía un puchero lleno de agua puesto al fuego.', 'Pirómides', NULL),
('El problema con la vida es que no tienes la oportunidad de practicar antes de hacerlo de verdad', 'Pirómides', NULL),
('—No sé qué hacer —dijo.
—No es para avergonzarse. Yo nunca he sabido qué hacer —replicó este en un fallido intento de humor—. Me he pasado la vida desconcertado. —Titubeó—. Creo que a eso lo llaman ser «humano».', 'Rechicero', NULL),
('La verdad no se podría resumir en una sola página. En la bañera de la historia, la verdad es tan difícil de aferrar como una pastilla de jabón, y aún más difícil de encontrar...', 'Rechicero', NULL),
('Nijel era una de esas personas que, cuando alguien dice "no mires ahora", vuelven inmediatamente la cabeza como un búho. Son esas mismas personas que, cuando les señalas una flor poco corriente que tienen al lado, se vuelven torpemente y la pisan. Si se pierden en un desierto, para encontrarlas solo hace falta poner en la arena algo pequeño y frágil, como un jarrón que ha pertenecido a tu familia durante generaciones, y esperar a que lo rompan.', 'Rechicero', 'Nijel el Destructor'),
('Quiero decir, dijo Ipslore amargamente, ¿qué hay en este mundo que realmente hace que valga la pena vivir?
La Muerte pensó en eso.
GATOS, dijo al rato. LOS GATOS SON AGRADABLES.', 'Rechicero', 'Muerte');

INSERT INTO citas_pratchett (cita, libro, personaje) VALUES
('Dicen que un poco de conocimiento es peligroso, pero no tanto como mucha ignorancia.', 'Ritos iguales', NULL),
('Ella sería ambas cosas, o ninguna. Y cuanto más intentaban impedírselo, más lo deseaba. Sería bruja, y también sería mago. Y ya verían todos.', 'Ritos iguales', 'Eskarina Herrero'),
('Rayos de luz azul salieron al pasillo, moviéndose y bailando mientras formas indefinidas se cruzaban en el brillo de la habitación. La luz era nebulosa y actínica, ese tipo de luz que hace que Steven Spielberg llame a abogados para defender sus derechos.', 'Ritos iguales', NULL),
('La furia era como la llama roja que aparece en la forja cuando la enciendes, todo brillo y chispas. En cambio, la que sentía ahora era diferente..., no provocaba chispas, era como la llamita azulada que corta el hierro. Le cosquilleaba dentro del cuerpo. Si no hacía algo, reventaría.', 'Ritos iguales', NULL),
('Los dos saborearon la estraña satisfacción de ser mucho más ignorantes que las personas normales, que solo eran ignorantes con respecto a cosas normales.', 'Ritos iguales', NULL),
('Las salas de los enanos resonaban con los martillazos, aunque era más que nada para dar ambiente. A los enanos les costaba trabajo pensar sin ruido de martillazos de fondo, de manera que los enanos bien situados económicamente gracias a trabajos administrativos pagaban a duendes para que golpearan pequeños yunques ceremoniales, y así mantener la imagen tradicional.', 'Ritos iguales', NULL),
('No sería gratis. Y Yaya conocía la magia de magos lo suficiente como para esar seguro de que el precio sería alto. Pero, si te preocupa el precio, ¿para qué entras en la tienda?', 'Ritos iguales', NULL),
('«Si vale la pena hacer una cosa, vale la pena aunque sea difícil.»', 'Ritos iguales', NULL),
('La biblioteca no solo contenía libros mágicos, encadenados a sus estantes y muy peligrosos. También contenía libros totalmente corrientes, impresos con tinta mundana sobre papel común. Sería un error pensar que esos libros no eran peligrosos por el mero hecho de que al leerlos no se encendiesen fuegos artificiales en el cielo. A veces leerlos surtía el efecto mucho más peligroso de encender fuegos artificiales en la intimidad del cerebro del lector.', 'Soul Music', NULL),
('Era una música triste. Pero agitó su tristeza como una bandera de batalla. Decía que el universo había hecho todo lo posible, pero que todavía estabas vivo.', 'Soul Music', NULL),
('Lo importante, decidió, era mantener la calma. Siempre había una explicación lógica para todo, incluso si había que inventársela.', 'Soul Music', 'Susan Sto Helit'),
('La gente siempre recordará las canciones que nunca tuvo ocasión de cantar. Y esas serán las más grandes de todas las canciones.', 'Soul Music', NULL),
('La invisibilidad era algo que iba con el trabajo, y él estaba acostumbrado a ella. Los humanos no veían a la Muerte hasta que no les quedaba otra elección.', 'Soul Music', 'Muerte'),
('—¡Las puertas no son lo bastante grandes como para que yo entre por ellas! —estalló Odro.
—Son unas puertas enormes —dijo Escurridizo.
—¡Pues no son lo bastante grandes para mí porque si alguien intenta meterme ahí dentro tendrá que meter también la calle, debido a que yo me estaré agarrando a ella!', 'Soul Music', NULL),
('En aquel lugar, si uno daba un salto lo bastante grande, podía ser libre. Solamente hacía falta darse cuenta que era una de las opciones posibles.', 'Tiempos interesantes', NULL),
('Sé algunas cosas de la gente que habla de sufrir por el bien de todos. ¡Nunca son ellos los que sufren, joder! ¡Siempre que oigáis a un hombre gritar: "¡Adelante, valientes camaradas!", veréis que es el que está detrás de la puta roca más grande y lleva el único casco que es realmente a prueba de flechas!', 'Tiempos interesantes', NULL),
('Tardaría varios millares de años en producir algún efecto, pero esa no era razón para rendirse.', 'Tiempos interesantes', NULL),
('—¿La barbarie? ¡Ja! Cuando matamos gente lo hacemos en su cara, mirándolos a los ojos, y estaremos encantados de invitarles a una copa en el otro mundo, sin rencores. Nunca he conocido a un bárbaro que rajara lentamente a la gente en cuartuchos, ni torturara a mujeres para que estuvieran guapas, ni pusiera veneno en la comida de la gente. ¿La civilización? ¡Si eso es la civilización, se la pueden meter donde el sol no brilla!', 'Tiempos interesantes', NULL),
('No robaban a la gente pobre, y no porque hubiera nada virtuoso en la gente pobre, sino porque los pobres no tenían dinero.', 'Tiempos interesantes', NULL),
('Rincewind escuchó. Y se le ocurrió que probablemente había algo cierto en la idea de que solo había un puñado de personas en el mundo. Había muchos cuerpos, sí, pero solo un puñado de personas. Era por eso que uno no paraba de encontrarse a la misma gente. Probablemente había algún molde en alguna parte.', 'Tiempos interesantes', 'Rincewind'),
('Golpea demasiado fuerte a un hombre y solamente podrás robarle una vez. Golpéale con la fuerza justa y podrás robarle todas las semanas', 'Tiempos interesantes', NULL),
('¡Aventuras! La gente hablaba de aquella idea como si fuera algo que valiera la pena, en lugar de un desastre compuesto de comida mala, falta de sueño y gente extraña que intentaba inexplicablemente clavar objetos afilados en partes de uno.', 'Tiempos interesantes', NULL),
('Bueno, pero es que somos magos —dijo Ridcully—. Se supone que nos dedicamos a inmiscuirnos en cosas que no entendemos. Si esperáramos a entender las cosas nunca haríamos nada.', 'Tiempos interesantes', 'Mustrum Ridcully'),
('—¿Por qué no los invitamos a cenar y los masacramos a todos mientras estén borrachos?
—Ya le has oído. Son setecientos mil.
—¡Ah! Entonces tendría que ser algo sencillo con pasta.', 'Tiempos interesantes', NULL),
('[...] Muerto. Intoxicación por metales.
—¿Cómo?
—Le clavaron tres espadas en el estómago.', 'Tiempos interesantes', NULL),
('—¿Sabes cuál es el gran plato en la costa?
—No
—La sopa de oreja de cerdo. Ahora, ¿Qué te dice eso sobre un lugar?
Rincewind se encogió de hombros
—¿Personas muy previsoras?
—Algun otro cabrón se roba el cerdo', 'Tiempos interesantes', 'Rincewind'),
('Se dice que los dioses juegan con las vidas de los hombres. Pero nadie sabe a qué juegan, ni por qué, ni quiénes son los peones, ni cuáles son las reglas del juego.
Es mejor no especular.', '¡Guardias! ¡Guardias!', NULL),
('La negra depresión que siempre albergaba se aprovechó de su estado de sobriedad y trasladó su morada a la punta de la lengua.', '¡Guardias! ¡Guardias!', 'Sam Vimes'),
('Un dragón era toda una metáfora de la existencia humana. Y por si fuera poco, también era una cosa enorme que volaba y escupía fuego.', '¡Guardias! ¡Guardias!', NULL),
('Recuerdo que había bebido para olvidar. La cosa no tenía mucho sentido, porque últimamente no conseguía recordar lo que quería olvidar.', '¡Guardias! ¡Guardias!', 'Sam Vimes'),
('Los dragones nobles no tienen amigos. Lo más parecido es un enemigo que todavía sigue vivo.', '¡Guardias! ¡Guardias!', NULL),
('Todo el mundo es culpable hasta que se demuestre lo contrario.', '¡Guardias! ¡Guardias!', NULL),
('El sexo es como la cocina: a veces te compras libros enteros llenos de recetas complicadas y fotos interesantes y en ocasiones cuando tienes mucha hambre te imaginanas unos banquetes de impresión. Sin embargo, al final del día te conformas felizmente con unos huevos con chorizo, siempre que estén bien preparados y tal vez acompañados por unas buenas patatas fritas...', '¡Guardias! ¡Guardias!', NULL),
('El bibliotecario le dirigió el tipo de mirada que otras personas reservan para quien dice cosas como «Pues no sé qué tiene de malo el genocidio».', '¡Guardias! ¡Guardias!', 'Bibliotecario'),
('Y yo no soy un héroe. No estoy en forma, y necesito una copa, y necesito una paga de cien dólares al mes sin extra para plumas. Ésa no es la paga de un héroe. El héroe se lleva reinos y princesas, y hace ejercicio a menudo, y cuando sonríe la luz arranca destellos de sus dientes, ting. El muy hijo de puta.', '¡Guardias! ¡Guardias!', NULL),
('No es la maldad creativa, aguda, de los grandes pecadores, sino una especie de oscuridad masiva de las almas. Pecado sin originalidad, se podría decir. Aceptan el mal, no porque digan sí, sino porque no dicen no.', '¡Guardias! ¡Guardias!', NULL),
('Era de edad indeterminada. Pero por su cinismo y por su hastío ante el mundo en general, que son algo así como la prueba del carbono para la personalidad, debía de tener unos siete mil años.', '¡Guardias! ¡Guardias!', NULL),
('Hay muchas visiones espantosas en el multiverso.
Pero, para un alma sintonizada con los sutiles ritmos vitales de una biblioteca, pocas de ellas son peores que un hueco allí donde debería haber un volumen.
Alguien había robado un libro.', '¡Guardias! ¡Guardias!', NULL),
('Esto es mío y eso es tuyo. Invade lo mío y te llevarás lo tuyo', '¡Voto a Bríos!', NULL);

COMMIT;

-- Comprobación opcional:
-- SELECT COUNT(*) AS total_citas FROM citas_pratchett;